	@feat_shoulder_width	tinyint,
	@head_bump_type			tinyint,
	@head_expression_type	tinyint,
	@feat_head_figure		tinyint
AS
/*
	exec GM_UserDataDA_UpdateCustomData @char_id=55819, ...
*/
BEGIN

	UPDATE	user_data
	SET		-- user data
			race = @race, 
			gender = @gender,
			name_id = @name_id,
			-- feat
			feat_version = @feat_version, 
			height_scale = @height_scale, --head_voice_type, 
			-- type
			head_hair_type = @head_hair_type, 
			head_face_type = @head_face_type, 
