			head_feat_type2 = @head_feat_type2, 
			head_bump_type = @head_bump_type, 
			head_expression_type = @head_expression_type, 
			-- color
			head_hair_color = @head_hair_color, 
			head_lip_color = @head_lip_color, 
			head_eye_color = @head_eye_color, 
			head_face_color = @head_face_color, 
			-- feat_data_enum
			feat_face_shape = @feat_face_shape,	-- 1
			feat_forehead_shape = @feat_forehead_shape, 
			feat_eye_position = @feat_eye_position, 
			feat_eye_glabella = @feat_eye_glabella, 
			feat_eye_length = @feat_eye_length, 
			feat_eye_height = @feat_eye_height, 
			feat_eye_shape = @feat_eye_shape, 
			feat_eye_tail = @feat_eye_tail, 
			feat_eyeblow_pos = @feat_eyeblow_pos, 
			feat_eyeblow_angle = @feat_eyeblow_angle, 
			feat_eyeblow_shape = @feat_eyeblow_shape, -- 11
			feat_nose_pos = @feat_nose_pos, 
			feat_nose_bridge = @feat_nose_bridge, 
			feat_nose_side = @feat_nose_side, 
			feat_nose_tip = @feat_nose_tip, 
			feat_cheek_shape = @feat_cheek_shape, 
			feat_mouth_pos = @feat_mouth_pos, 
			feat_mouth_size = @feat_mouth_size, 
			feat_lip_thickness = @feat_lip_thickness, 
			feat_lip_tail = @feat_lip_tail, 
			feat_lip_shape = @feat_lip_shape,  -- 21
			feat_jaw_pos = @feat_jaw_pos, 
			feat_jaw_shape = @feat_jaw_shape, 
			feat_ear_shape = @feat_ear_shape, 
			feat_head_size = @feat_head_size, 
			feat_neck_thickness = @feat_neck_thickness, 
			feat_neck_length = @feat_neck_length, 
			feat_shoulder_size = @feat_shoulder_size, 
			feat_upper_size = @feat_upper_size, 
			feat_bust_size = @feat_bust_size, 
			feat_waist_size = @feat_waist_size,	-- 31
			feat_hip_size = @feat_hip_size, 
			feat_arm_thickness = @feat_arm_thickness, 
			feat_hand_size = @feat_hand_size, 
			feat_leg_thickness = @feat_leg_thickness, 
			feat_foot_size = @feat_foot_size, 
			feat_face_ratio = @feat_face_ratio, 
