procedures.aion_PutHouseScriptInstantToField:
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[aion_PutHouseScriptInstantToField]
	@char_id INT,
	@addr_id INT
AS
BEGIN
	SET NOCOUNT ON;

	DECLARE @slot_id INT;
	DECLARE @script_size SMALLINT;
	DECLARE @script_data VARBINARY(3072);

	DECLARE script_cursor CURSOR FOR (SELECT slot_id, script_size, script_data FROM house_instant_script WHERE char_id = @char_id);
	OPEN script_cursor;
	FETCH NEXT FROM script_cursor INTO @slot_id, @script_size, @script_data;
	WHILE @@FETCH_STATUS = 0
	BEGIN
		EXEC aion_SetHouseFieldScript @addr_id, @slot_id, @script_size, @script_data;
		FETCH NEXT FROM script_cursor INTO @slot_id, @script_size, @script_data;
	END
	CLOSE script_cursor;
	DEALLOCATE script_cursor;

	DELETE FROM house_instant_script WHERE char_id = @char_id
END

