CREATE procedure [dbo].[aion_PutItem]
	@dbId       bigint OUTPUT,
	@nCharId	int,
	@nNameId	int, 
	@nSlotId	smallint, 
	@nAmount	bigint,
	@nTid		bigint,
	@nSlotNum	tinyint,	
	@nWarehouse	int,
	@soulBound	tinyint,
	@enchantCount	tinyint,
	@skinNameId	int,	
	@statEnchantName0	int,	
	@statEnchantName1	int,
	@statEnchantName2	int,	
	@statEnchantName3	int,	
	@statEnchantName4	int,	
	@statEnchantName5	int,	
	@optionCount smallint,		
	@dye_info int,
	@nProcToolNameId int,
	@nExpiredTime	int,
	@producer nvarchar(20),
	@buyamount smallint,
	@buyduration smallint,
	@obtainSkinType tinyint,
	@expireSkinTime	int,
	@dynamicProperty int,
	@serverOfOrigin smallint,
	@expireDyeTime	int,
	@random_option	smallint,
	@limit_enchant_count	smallint,
	@reidentify_count tinyint,	
	@authorizeCount tinyint,
	@vanishPoint int,	
	@enchantProbAddition int,
	@optionProbAddition  int,
	@keyNameId int,
	@exceedState tinyint,
	@exceedSkillId1  int,
	@exceedSkillId2  int,
	@exceedSkillId3  int,
	@baseSkillId int
as
set nocount on
INSERT user_item (char_id, name_id, slot_id, amount,tid,slot,warehouse,
		producer, expired_time,buy_amount, buy_duration,
		dynamic_property, server_of_origin)
VALUES (@nCharId, @nNameId, @nSlotId, @nAmount, @nTid, @nSlotNum, @nWarehouse,
		@producer, @nExpiredTime, @buyamount, @buyduration,
		@dynamicProperty, @serverOfOrigin)

IF @@ERROR <> 0
	return
set @dbId = @@IDENTITY

--if (@statenchantname0 + @statenchantname1+@statenchantname2 + @statenchantname3 + @statenchantname4+@statenchantname5+@enchantCount+@soulBound + @optionCount + @dye_info + @limit_enchant_count > 0 )
if (
	(@random_option > 0) or (@skinNameId > 0) or (@statenchantname0 > 0) or (@statenchantname1 > 0) or (@statenchantname2 > 0) or (@statenchantname3 > 0) 
	or (@statenchantname4 > 0) or (@statenchantname5 > 0) or (@nProcToolNameId > 0) or (@enchantCount > 0) or (@soulBound > 0) or (@optionCount > 0) or (@dye_info != 0) 
	or (@limit_enchant_count > 0) or (@authorizeCount > 0) or (@vanishPoint > 0) or (@enchantProbAddition > 0) or (@optionProbAddition > 0) or (@keyNameId > 0)
	)
begin
insert user_item_option (id, char_id, soul_bound, enchant_count, skin_name_id, 
		stat_enchant_name0, stat_enchant_name1, stat_enchant_name2, 
		stat_enchant_name3, stat_enchant_name4, stat_enchant_name5, 
		option_count, dye_info, proc_tool_nameid, obtain_skin_type, expire_skin_time,
		expire_dye_time, random_option, limit_enchant_count, reidentify_count,
		authorize_count, vanish_point, 		
		enchant_prob_addition, option_prob_addition,
		KeyNameId, exceedState, ExceedSkillId1, ExceedSkillId2, ExceedSkillId3,
		BaseSkillId
		)
		values
		(@dbId, @nCharId,@soulBound,@enchantCount,@skinNameId, 
		@statEnchantName0, @statEnchantName1,
		@statEnchantName2, @statEnchantName3,
		@statEnchantName4, @statEnchantName5,
		@optionCount, @dye_info, @nProcToolNameId,@obtainSkinType, @expireSkinTime,
		@expireDyeTime, @random_option,@limit_enchant_count, @reidentify_count,
		@authorizeCount, @vanishPoint,		
		@enchantProbAddition, @optionProbAddition,
		@keyNameId, @exceedState, @exceedSkillId1, @exceedSkillId2, @exceedSkillId3,
		@baseSkillId
		)
end
set nocount off

return

