procedures.aion_UpdateDisassemblyRetry:
CREATE procedure [dbo].[aion_UpdateDisassemblyRetry]
	@charId int, 
	@itemId bigInt,
	@retryCount int, 
	@isDelete tinyint, 
	@name1 int,
	@count1 int,
	@name2 int,
	@count2 int,
	@name3 int,
	@count3 int,
	@name4 int,
	@count4 int,
	@name5 int,
	@count5 int
as 
begin 
	begin tran
	update user_disassembly_retry set retryCount = @retryCount, isDelete = @isDelete, nameId1 = @name1, ItemCount1 = @count1, 
		nameId2 = @name2, ItemCount2 = @count2, nameId3 = @name3, ItemCount3 = @count3, nameId4 = @name4, ItemCount4 = @count4, 
		nameId5 = @name5, ItemCount5 = @count5, UpdateDate = GETDATE()
	where charId = @charId and ItemId = @itemId 
	
	if @@ROWCOUNT = 0
	begin
		insert into user_disassembly_retry values(@charId, @itemId, @retryCount, @isDelete, @name1, @count1, 
				@name2, @count2, @name3, @count3, @name4, @count4, @name5, @count5, GETDATE())
	end
	commit
end

