CREATE PROCEDURE [dbo].[aion_GetVendorAverageDark]
	@make_date INT,
	@get_only_oneweek INT
AS
BEGIN
	SET NOCOUNT ON;

	-- SELECT name_id, sold_unit_price, sold_date FROM vendor_average_dark;
	
	-- SELECT * FROM A FULL OUTER JOIN B WHERE A.name_id = B.name_id;
	-- SELECT name_id, averge_unit_price, entire_sold_number FROM vendor_average_dark_last_result WHERE create_date > @date_from;
	-- SELECT name_id, AVG(sold_unit_price), COUNT(*) FROM vendor_average_dark GROUP BY name_id;
	
	-- BEGIN TRAN;
	
	DECLARE @cursqldate DATETIME = GETDATE();
	
	DECLARE @name_id BIGINT;
	DECLARE @avg BIGINT;
	DECLARE @num INT;

	DECLARE @last_avg BIGINT;
	DECLARE @last_num INT;
	DECLARE @last_date INT;

	-- calculate average from log, log tbl will be truncated		
	DECLARE cur_log CURSOR FOR (SELECT name_id, AVG(sold_unit_price), COUNT(*) FROM vendor_average_dark WHERE sold_date < @make_date GROUP BY name_id);
	OPEN cur_log;
	FETCH NEXT FROM cur_log INTO @name_id, @avg, @num;
	
	WHILE @@FETCH_STATUS = 0
	BEGIN
		-- find last average
		SELECT @last_avg = average_unit_price, @last_num = entire_sold_number, @last_date = create_date FROM vendor_average_dark_last_result WHERE name_id = @name_id;
		
		IF @last_avg IS NULL
		BEGIN
			-- new sold average
			INSERT vendor_average_dark_last_result (name_id, average_unit_price, entire_sold_number, create_date, update_date)
			VALUES (@name_id, @avg, @num, @make_date, @make_date);
		END
		ELSE
		BEGIN
		/* changes: just make average one week, not all before make time
			IF (@last_date > @make_date)
			BEGIN
				-- update last average
				UPDATE vendor_average_dark_last_result
				SET average_unit_price = (((@last_num * @last_avg) + (@num * @avg)) / (@last_num + @num)), entire_sold_number = @last_num + @num, update_date = @make_date, update_datetime = @cursqldate
				WHERE name_id = @name_id;
			END
			ELSE
			BEGIN
		*/
				-- replace old average to new
				UPDATE vendor_average_dark_last_result 
				SET average_unit_price = @avg, entire_sold_number = @num, update_date = @make_date, update_datetime = @cursqldate
				WHERE name_id = @name_id;
		/*
			END
		*/			
		END
		
		FETCH NEXT FROM cur_log INTO @name_id, @avg, @num;
	END
	CLOSE cur_log;
	DEALLOCATE cur_log;
	
	-- COMMIT TRAN
	
	-- delete completed sold log
	DELETE FROM vendor_average_dark WHERE sold_date < @make_date;
	
	-- select result to server
	IF (@get_only_oneweek > 0)
	BEGIN
		SELECT name_id, average_unit_price FROM vendor_average_dark_last_result WHERE update_date = @make_date;
	END
	ELSE
	BEGIN
		SELECT name_id, average_unit_price FROM vendor_average_dark_last_result;
	END
END

