procedures.sd_Punish:
/**
版    本: 1
作    者: Sun
创建日期: 2010-11-22
描    述: 封停角色
结 果 集：
返 回 值:0，正常值
		 -900001，有未提交的事务
		 -900002，错误的角色ID
		 -900004，封停记录插入错误
**/
CREATE PROCEDURE [dbo].[sd_Punish]
	@Character_ID	int,	--//封停角色ID
	@Punish_Policy	nvarchar(30),	--//封停策略
	@Punish_Code	int,	--//1：永久;50：短期;100：角色限制移动;101：角色聊天限制;102：个人商城限制
	@Play_Block		tinyint,--//1：不能登录；0：能登录
	@Punish_Min		int,	--//封停分钟
	@Punish_Reason	nvarchar(200) --//封停原因，会显示在界面上
AS
SET NOCOUNT ON;
SET XACT_ABORT ON;

DECLARE @Return_Value	int,	--//返回值
		@Account_ID		int		--//Account ID

IF XACT_STATE() = -1
BEGIN
	SET @Return_Value = -900001;
	GOTO ErrorHandler;
END

--查找对应的封停帐号ID
SELECT	@Account_ID = Account_ID
	FROM User_Data WITH(NOLOCK)
	WHERE Char_ID = @Character_ID;

IF @@ROWCOUNT = 0
BEGIN
	SET @Return_Value = -900002;
	GOTO ErrorHandler;
END
	
--封停帐号
BEGIN TRY	
INSERT INTO User_Punishment
	(Account_ID,
	Char_ID,
	Play_Block,
	Status,
	Punish_Code,
	Start_Date,
	End_date,
	Remain_Minute,
	Punish_Reason,
	Login_ID,
	Login_Nm) 
VALUES (@Account_ID,
		@Character_ID,
		@Play_Block,
		0,
		@Punish_Code,
		GetDate(),
		DATEADD(minute, @Punish_Min, GetDate()), 
		@Punish_Min, 
		@Punish_Reason,
		'punish_ur',
		'(' + @Punish_Policy + ')(-1)');
END TRY
BEGIN CATCH
	SET @Return_Value = -900004;
	GOTO ErrorHandler;
END CATCH;
	
RETURN 0;

ErrorHandler:
IF XACT_STATE() <> 0
	ROLLBACK TRANSACTION;
RETURN @Return_Value;

