		@Punish_Reason	nvarchar(200), --//封停原因，会显示在界面上
		@Punish_Times	int		--//封停次数（同一种封停策略第几次封停）

IF XACT_STATE() = -1
BEGIN
	SET @Return_Value = -900001;
	GOTO ErrorHandler;
END

--查找对应的封停帐号ID
SELECT	@Account_ID = Account_ID
	FROM User_Data WITH(NOLOCK)
	WHERE Char_ID = @Character_ID;

IF @@ROWCOUNT = 0
BEGIN
	SET @Return_Value = -900002;
	GOTO ErrorHandler;
END

--SELECT @Punish_Times = COUNT(*) + 1
--	FROM User_Punishment
--	WHERE Char_ID = @Character_ID
--	AND Login_ID = CAST(@Punish_Policy AS nvarchar(10));
--
--SELECT	@Punish_Code = Punish_Code,
--		@Play_Block = Play_Block,
--		@Punish_Min = Punish_Minute,
--		@Punish_Reason = Punish_Reason
--	FROM sd_Punish_Policy
--	WHERE Policy_ID = @Punish_Policy
--	AND @Punish_Times BETWEEN Start_Times AND End_Times;

SELECT	@Punish_Code = Punish_Code,
		@Play_Block = Play_Block,
		@Punish_Min = Punish_Minute,
		@Punish_Reason = Punish_Reason
	FROM sd_Punish_Type
	WHERE Punish_Type = @Punish_Type;

IF @@ROWCOUNT = 0
BEGIN
	SET @Return_Value = -900003;
	GOTO ErrorHandler;
END
	
--封停帐号
BEGIN TRY	
INSERT INTO User_Punishment
	(Account_ID,
	Char_ID,
	Play_Block,
	Status,
	Punish_Code,
	Start_Date,
	End_date,
	Remain_Minute,
	Punish_Reason,
	Login_ID,
	Login_Nm) 
VALUES (@Account_ID,
		@Character_ID,
		@Play_Block,
		0,
		@Punish_Code,
		GetDate(),
		DATEADD(minute, @Punish_Min, GetDate()), 
		@Punish_Min, 
		@Punish_Reason,
		'punish_ur',
		'(' + @Punish_Policy + ')(' + CAST(@Punish_Type AS nvarchar(10)) + ')');
END TRY
BEGIN CATCH
	SET @Return_Value = -900004;
	GOTO ErrorHandler;
END CATCH;
	
RETURN 0;

ErrorHandler:
IF XACT_STATE() <> 0
	ROLLBACK TRANSACTION;
RETURN @Return_Value;

