CREATE procedure [dbo].[aion_SetItemEnchant]
	@id 		bigint,
	@soulBound	tinyint,
	@enchantCount	tinyint,
	@skinNameId	int,	
	@statEnchantName0	int,	
	@statEnchantName1	int,	
	@statEnchantName2	int,	
	@statEnchantName3	int,	
	@statEnchantName4	int,	
	@statEnchantName5	int,		
	@procToolNameId int,
	@obtainSkinType	tinyint,
	@expireSkinTime int,
	@limit_enchant_count	smallint,	
	@authorize_count tinyint,
	@vanish_point int,	
	@enchantProbAddition int,
	@optionProbAddition  int,
	@keyNameId int,
	@exceedState tinyint,
	@exceedSkillId1  int,
	@exceedSkillId2  int,
	@exceedSkillId3  int, 
	@baseSkillId int
as
set nocount on
declare @nCharId int
declare @mainItemId bigint

if (@enchantCount = 0) --보조무기이고, enchant가 0으로 오면, 기존 enchant값을 유지한다.
begin 
	select @mainItemId = ISNULL(main_item_dbid, 0)from user_item with (nolock) where id = @id 
	
	if (@mainItemId > 0) --적어도 메인 아이템이 있다면, enchant도 있을 것이다.
	begin
		select @enchantCount = ISNULL(enchant_count, 0) from user_item_option with (nolock)  where id=@id
	end
end
SET NOCOUNT OFF

UPDATE user_item_option
SET soul_bound = @soulBound, enchant_count = @enchantCount, skin_name_id = @skinNameId,
	stat_enchant_name0 = @statEnchantName0,
	stat_enchant_Name1 = @statEnchantName1,
	stat_enchant_Name2 = @statEnchantName2,
	stat_enchant_Name3 = @statEnchantName3,
	stat_enchant_Name4 = @statEnchantName4,
	stat_enchant_Name5 = @statEnchantName5,		
	proc_tool_nameid = @procToolNameId, 
	obtain_skin_type = @obtainSkinType, expire_skin_time = @expireSkinTime,
	limit_enchant_count = @limit_enchant_count,
	authorize_count = @authorize_count, vanish_point=@vanish_point,	
	enchant_prob_addition = @enchantProbAddition,
	option_prob_addition = @optionProbAddition,
	KeyNameId = @keyNameId,
	exceedState = @exceedState,
	exceedSkillId1 = @exceedSkillId1, 
	exceedSkillId2 = @exceedSkillId2, 
	exceedSkillId3 = @exceedSkillId3,
	baseSkillId = @baseSkillId
WHERE id=@id


if @@ROWCOUNT = 0
begin
	select @nCharId = char_id  from user_item where id = @id
	
	insert user_item_option (id, char_id, soul_bound, enchant_count, skin_name_id, 
			stat_enchant_name0, stat_enchant_Name1, 
			stat_enchant_Name2, stat_enchant_Name3, 
			stat_enchant_Name4, stat_enchant_Name5, 
			proc_tool_nameid, 
			obtain_skin_type, expire_skin_time, limit_enchant_count, 
			authorize_count, vanish_point,			
			enchant_prob_addition, option_prob_addition,
			KeyNameId, exceedState, ExceedSkillId1, ExceedSkillId2, ExceedSkillId3,
			baseSkillId
			)
			values
			(@Id, @nCharId,@soulBound,@enchantCount,@skinNameId, 
			@statEnchantName0, @statEnchantName1,
			@statEnchantName2, @statEnchantName3,
			@statEnchantName4, @statEnchantName5,
			@procToolNameId,
			@obtainSkinType, @expireSkinTime,
			@limit_enchant_count,
			@authorize_count, @vanish_point,			
			@enchantProbAddition, @optionProbAddition,
			@keyNameId, @exceedState, @exceedSkillId1, @exceedSkillId2, @exceedSkillId3,
			@baseSkillId
			)
	if @@ERROR <> 0
	begin
		UPDATE user_item_option
		SET soul_bound = @soulBound, enchant_count = @enchantCount, skin_name_id = @skinNameId,
			stat_enchant_name0 = @statEnchantName0,
			stat_enchant_Name1 = @statEnchantName1,
			stat_enchant_Name2 = @statEnchantName2,
			stat_enchant_Name3 = @statEnchantName3,
			stat_enchant_Name4 = @statEnchantName4,
			stat_enchant_Name5 = @statEnchantName5,		
			proc_tool_nameid = @procToolNameId, 
			obtain_skin_type = @obtainSkinType, expire_skin_time = @expireSkinTime,
			limit_enchant_count = @limit_enchant_count,
			authorize_count = @authorize_count, vanish_point=@vanish_point,			
			enchant_prob_addition = @enchantProbAddition,
			option_prob_addition = @optionProbAddition, 
			KeyNameId = @keyNameId,
			exceedState = @exceedState,
			exceedSkillId1 = @exceedSkillId1, 
			exceedSkillId2 = @exceedSkillId2, 
			exceedSkillId3 = @exceedSkillId3,
			baseSkillId = @baseSkillId
		WHERE id=@id
	end
end
SET NOCOUNT OFF

