procedures.GM_GuildDA_SrchGuildWarehouseHistory:
CREATE proc [dbo].[GM_GuildDA_SrchGuildWarehouseHistory]
			@guild_id nvarchar(10),
			@view_count int,
			@top_count int
		as			
			set nocount on
			set transaction isolation level read uncommitted
			set ansi_warnings off	

			select top(@view_count) id, guild_id, eventdate, eventtype, eventparam, eventparam2
			from	guild_warehouse_history(nolock)
			where	guild_id=@guild_id and id not in (select top(@top_count) id from guild_warehouse_history(nolock) where guild_id=@guild_id order by id desc) 
			order by id desc

