CREATE procedure [dbo].[aion_ReplaceAbnormalStatus] 
	@nCharId int,
	@nSkillId int,
	@nSkillLevel smallint,
	@nTargetSlot	tinyint, 
	@nRemain1	int,
	@nRemain2	int,
	@nRemain3	int,
	@nRemain4	int,
	@nIntervalValue1	int,
	@nIntervalValue2	int,
	@nIntervalValue3	int,
	@nIntervalValue4	int
as
SET NOCOUNT ON
if EXISTS (SELECT char_id FROM user_abnormal_status(UPDLOCK) WHERE  char_id=@nCharId and skill_id=@nSkillId) 
begin
	UPDATE user_abnormal_status
	SET skill_level=@nSkillLevel, target_slot=@nTargetSlot, 
		effect_remain1=@nRemain1, effect_remain2=@nRemain2, effect_remain3=@nRemain3, effect_remain4=@nRemain4, 
		interval_value1=@nIntervalValue1, interval_value2=@nIntervalValue2, interval_value3=@nIntervalValue3, interval_value4=@nIntervalValue4	
	WHERE  char_id=@nCharId and skill_id=@nSkillId 
end
else
begin
	INSERT user_abnormal_status(char_id, skill_id, skill_level, target_slot, effect_remain1, effect_remain2, effect_remain3, effect_remain4, interval_value1, interval_value2, interval_value3, interval_value4)
	VALUES (@nCharId, @nSkillId, @nSkillLevel, @nTargetSlot, @nRemain1, @nRemain2, @nRemain3, @nRemain4, @nIntervalValue1,  @nIntervalValue2,  @nIntervalValue3,  @nIntervalValue4)
end
