CREATE PROCEDURE [dbo].[aion_savelimitedsales]
	-- Add the parameters for the stored procedure here
	@npcid bigint,	
	@checktime bigint,
	@totalstock int,
	@itemid bigint,
	@curstock smallint,
	@limitbuy smallint,
	@limitnum smallint,
	@turncnt smallint,
	@charid bigint,
	@count bigint,
	@purchasetime bigint
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    update npc_limited_sales set cur_stock = @curstock, limit_buy = @limitbuy, limit_num = @limitnum, turn_count = @turncnt where npc_id = @npcid and item_id=@itemid and delete_flag = 0
    
    if @@ROWCOUNT = 0
		insert into npc_limited_sales (npc_id, check_time, total_stock, item_id, cur_stock, limit_buy, limit_num, turn_count) values(@npcid, @checktime, @totalstock, @itemid, @curstock, @limitbuy, @limitnum, @turncnt)
	
	update npc_limited_sales set check_time=@checktime, total_stock=@totalstock where npc_id = @npcid and delete_flag = 0
	
	update npc_user_sales_log set purchase_time=@purchasetime, turn_count = @turncnt, count=@count where npc_id=@npcid and item_id = @itemid and char_id=@charid and delete_flag = 0
	
	if @@ROWCOUNT = 0
		insert into npc_user_sales_log (npc_id, item_id, char_id, purchase_time, count, turn_count) values (@npcid, @itemid, @charid, @purchasetime, @count, @turncnt)
	
END

