procedures.GM_LegionDominionDA_Srch:
CREATE PROC [dbo].[GM_LegionDominionDA_Srch]
			@world_id		int,
			@legion_id		int	= 0,
			@legion_name	nvarchar(32) = '',
			@dominion_id	int	= 0,
			@page_num		int	= 1,
			@view_count		int	= 1000,
			@order_col		varchar(200) = 'dominion_id, score desc, played_time_in_sec, game_end_time'
		AS
			set nocount on
			set transaction isolation level read uncommitted

			declare @query nvarchar(2000)
			declare @where nvarchar(1000)
			
			set @where = '
				where	server_id = ' + convert(varchar, @world_id)
			if (@legion_id != 0)
				set @where = @where + '
				and		legion_id = ' + convert(varchar, @legion_id)
			if (@legion_name != '')
				set @where = @where + '
				and		name = ''' + @legion_name + ''''
			if (@dominion_id != 0)
				set @where = @where + '
				and		dominion_id = ' + convert(varchar, @dominion_id)
			else
				set @where = @where + '
				and		dominion_id != 0'
				
			set @query = '
				select	top (' + convert(varchar, @view_count) + ') x.*, ISNULL(x.name, ''unknown'') as legion_name
				from (
					select	top (' + convert(varchar, @page_num*@view_count) + ') ROW_NUMBER() over (order by ' + @order_col + ') as num, legion_id, g.name, dominion_id, score, played_time_in_sec, game_end_time, take_over_processed_time, server_id
					from	legion_dominion_rankings d
					LEFT JOIN guild g (nolock) on d.legion_id = g.id '
				+	@where + '
				) x '
				+ @where + ' 
				and		num > ' + convert(varchar, (@page_num-1)*@view_count)
				+ '
				order by ' + @order_col

			EXEC (@query)

