CREATE PROCEDURE [dbo].[aion_AddOfflineBuddy] 
	@charId int,
	@inviterId int,
	@inviterName nvarchar(50),
	@message nvarchar(MAX),
	@level int,
	@class int, 
	@gender int
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;
	
	if exists (select inviter_id from user_buddy_offline with(nolock) where user_id = @charid and inviter_id = @inviterId)
		return 12;
	
	if exists (select inviter_id from user_buddy_offline with(nolock) where user_id = @inviterId and inviter_id = @charId)	
		return 19;
		
	declare @buddyCount int
	declare @offCount int
	declare @interCount int
	
	select @buddyCount = COUNT(*) from user_buddy1 where char_id = @charId 
	select @offCount = COUNT(*) from user_buddy_offline where user_id = @charId
	select @interCount = COUNT(*) from user_buddy_inter where char_id = @charid
	
	if (@buddyCount + @offCount + @interCount>= 100) 
		return 14;
	
	select @buddyCount = COUNT(*) from user_buddy1 where char_id = @inviterid
	select @offCount = COUNT(*) from user_buddy_offline where inviter_id = @inviterid
	select @interCount = COUNT(*) from user_buddy_inter where char_id = @inviterid
	
	if (@buddyCount + @offCount+@interCount >= 100) 
		return 13;
	
	insert into user_buddy_offline (user_id, inviter_id, inviter_name, inviter_msg, userlevel, userclass, gender) values (@charid, @inviterId, @inviterName, @message, @level, @class, @gender)
	
	return 11;
END

