-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[aion_AnswerOfflineBuddy] 
	@charId int,
	@charname varchar(20),
	@inviterId int,	
	@invitername varchar(20),
	@level int output,
	@class int output,
	@gender int output,
	@worldnum int output, 
	@todayword varchar(53) output
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;	
		
	declare @result int
	
	set @level = 0
	set @class = 0
	set @gender = 0
	set @worldnum = 0
	set @todayword = N''
	
	if EXISTS(SELECT char_id FROM user_buddy1 WHERE char_id = @charId and buddy_id = @inviterId)
		return 2	--already		
	
	if not exists (select char_id from user_data(nolock) where char_id = @inviterId and race = (select race from user_data(nolock) where char_id = @charId))
		return 3   -- not exist (and race check)
	
	declare @buddyCount int
	declare @offCount int
	
	select @buddyCount = COUNT(*) from user_buddy1 where char_id = @charId 	
	
	if (@buddyCount >= 200) 
		return 5; --out of buddy
	
	select @buddyCount = COUNT(*) from user_buddy1 where char_id = @inviterid	
	
	if (@buddyCount >= 200) 
		return 5;	
	
	INSERT user_buddy1 (char_id, buddy_id, delete_flag) VALUES (@inviterid, @CharId, 0)	--초대 대상이 오프라인이므로, 이때 추가해주기.
	
	select @level = lev, @class = class, @gender = gender, @worldnum = world, @todayword = daily_comment from user_data (nolock) where char_id = @inviterId 
	return 0;
END

