procedures.GM_UserItemDAO_InsertUpdateSealedItem:
CREATE PROCEDURE [dbo].[GM_UserItemDAO_InsertUpdateSealedItem]
	@id					bigint,
	@sealExpiredTime	int,
	@sealState			tinyint,
	@char_id			int
AS

	IF NOT EXISTS ( SELECT 1 FROM user_item_sealed WHERE id = @id )
	BEGIN
		INSERT INTO user_item_sealed
		VALUES
		(
			@id, 
			@sealExpiredTime,
			@sealState,
			@char_id
		)
	END
	ELSE
	BEGIN
		UPDATE	user_item_sealed
		SET		sealExpiredTime = @sealExpiredTime,
				sealState = @sealState,
				char_id = @char_id
		WHERE	id = @id
	END

