procedures.aion_BlockOfflineBuddy:
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
Create PROCEDURE [dbo].[aion_BlockOfflineBuddy] 
	@charId int,
	@inviterId int	
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;	
		
	declare @result int
	
	if exists (select buddy_id from user_buddy1 where char_id = @charid and  buddy_id = @inviterId and delete_flag = 0)
		return 4;	-- BKT_INVALID
	if exists (select block_id from user_block where char_id = @charid and block_id = @inviterId)
		return 0;	--이미 있지만 에러가 없다.
	
	declare @blockcount int
	
	select @blockcount = COUNT(*) from user_block where char_id = @charid
	
	
	if (@blockcount >= 200) 
		return 3;
	
	insert into user_block (char_id, block_id, comment) values (@charId, @inviterId, '')
	
	return 0;
END

