procedures.aion_SetChallengeTaskComplete:
CREATE PROCEDURE [dbo].[aion_SetChallengeTaskComplete]
	@nTaskDbId as bigint,
	@nStatus as tinyint,
	@nCompleteCnt as smallint,
	@nLastCompleteTime as int,
	@nRepeat as tinyint
AS
BEGIN
	SET NOCOUNT ON;
	If @nRepeat=1
	Begin
		Update challenge_task 
			Set status=@nStatus, complete_count=@nCompleteCnt, last_complete_time=@nLastCompleteTime
			Where id=@nTaskDbId;
		Update challenge_task_quest
			Set complete_count=0 Where challenge_task_id=@nTaskDbId;
		Update challenge_task_contributor
			Set score=0 Where challenge_task_id=@nTaskDbId;
	End
	Else
	Begin
		Update challenge_task 
		Set status=@nStatus, complete_count=@nCompleteCnt, last_complete_time=@nLastCompleteTime
		Where id=@nTaskDbId;
	End
END

