procedures.aion_SetMonsterAchievementRewardReceived:
CREATE PROC [dbo].[aion_SetMonsterAchievementRewardReceived]
	@outGradeOfReward	int output,
	@char_id			int,
	@achieve_id			int,
	@reward_received	tinyint
AS
	SET NOCOUNT ON
	
	SET		@outGradeOfReward = -1

	UPDATE	user_monster_achievement
	SET		reward_received = @reward_received, @outGradeOfReward = @reward_received
	WHERE	char_id = @char_id AND achieve_id = @achieve_id AND reward_received = @reward_received - 1
	
	return @@ROWCOUNT

