procedures.aion_MailWriteSys_20111227:
CREATE PROCEDURE [dbo].[aion_MailWriteSys_20111227]
	@to_id			INT,
	@to_name 		NVARCHAR(20),
	@from_id		INT,	
	@from_name		NVARCHAR(20),
	@title			NVARCHAR(20),
	@content		NVARCHAR(1000),
	@item_id		BIGINT,
	@item_nameid	INT,
	@item_amount	BIGINT,
	@money			BIGINT,
	@warehouse		INT,
	@arrive_time	INT,
	@express_mail   INT
AS
BEGIN
	SET NOCOUNT ON;

	IF (@item_id <> 0)
	BEGIN
		UPDATE user_item SET warehouse = @warehouse, char_id = @to_id WHERE id = @item_id
		update user_item_option set char_id = @to_id where id = @item_id
	END

	INSERT INTO user_mail (to_id, to_name, from_id, from_name, title, content, item_id, item_nameid, item_amount, money, arrive_time, express_mail) VALUES(@to_id, @to_name, @from_id, @from_name, @title, @content, @item_id, @item_nameid, @item_amount, @money, @arrive_time, @express_mail)

	SET NOCOUNT OFF;
END

