	UPDATE user_promotion_cooltime
	SET last_promotion_time = @nLastPromotionTime, received_item_count = @nReceivedItemCount, cycle_received_item_count = @nCycleReceivedItemCount, cycle_next_reset_time = @nCycleNextResetTime	
	WHERE char_id=@nCharId and promotion_id=@nPromotionId
