procedures.GM_UserCustomAnimationDAO_InsertUpdateAn:
CREATE PROCEDURE [dbo].[GM_UserCustomAnimationDAO_InsertUpdateAnimation]
	@char_id int,
	@animation_id smallint,
	@animation_type tinyint,
	@useState tinyint,
	@expire_time int
AS	
	IF NOT EXISTS ( SELECT 1 FROM user_customAnimation (nolock) WHERE char_id = @char_id AND animation_id = @animation_id )
	BEGIN
		INSERT INTO user_customAnimation
		(
			char_id,	
			animation_id, 
			animation_type,	
			useState, 
			expire_time
		)
		VALUES
		(
			@char_id, 
			@animation_id, 
			@animation_type, 
			@useState, 
			@expire_time
		)
	END
	ELSE
	BEGIN
		UPDATE	user_customAnimation
		SET		animation_type = @animation_type, 
				useState = @useState, 
				expire_time = @expire_time
		WHERE	char_id = @char_id
		AND		animation_id = @animation_id
	END

