CREATE procedure [dbo].[aion_PutBuilderCommandLog_20110225]
	@nWorldId		int,
	@strUserId		nvarchar(20),	
	@nType			tinyint,
	@nLevel			tinyint,
	@strCommand		nvarchar(40),
	@strParameter	nvarchar(100),
	@commandFrom	tinyint = 0,
	@resultMessage	nvarchar(1024) = ''
AS
BEGIN

if EXISTS (SELECT BUILDER_LOG_ID FROM builder_log(UPDLOCK) WHERE CHAR_NM = @strUserId and (@commandFrom = 1)) 
begin
	UPDATE builder_log 
	SET world_id=@nWorldId, build_nm=@strCommand, build_parameter=@strParameter, builder_type=@nType, builder_lv=@nLevel, command_from=@commandFrom, result_message = @resultMessage + result_message
	where CHAR_NM = @strUserId and (@commandFrom = 1)
end
else
begin
	INSERT builder_log ( world_id, char_nm, build_nm, build_parameter, builder_type, builder_lv, regdate, command_from, result_message )
	VALUES ( @nWorldId, @strUserId, @strCommand, @strParameter, @nType, @nLevel, GETDATE(), @commandFrom, @resultMessage )
end

END

