CREATE PROCEDURE [dbo].[aion_PutChallengeTask]
	@nTaskDbId bigint OUTPUT,
	@nUnionId int,
	@nType tinyint,
	@nTaskNameId int,
	@nStatus tinyint
AS
BEGIN
	SET NOCOUNT ON;

	IF EXISTS (Select id From challenge_task(nolock) Where union_id=@nUnionId and type=@nType and task_name_id=@nTaskNameId)
		Begin
			return 1;	-- 중복 도전 과제
		End
	ELSE
		Begin
			Insert Into challenge_task(union_id, type, task_name_id, status, complete_count, last_complete_time)
				Values(@nUnionId, @nType, @nTaskNameId, @nStatus, 0, 0);

			IF @@ERROR <> 0
				Begin
					return 2; -- insert 실패	
				End
			
			set @nTaskDbId = @@IDENTITY
		End
	return 0;
END

