-- 최종 수정일 : 2008/03/03 spinel

CREATE PROCEDURE [dbo].[aion_PutChar_20120516]
	-- Add the parameters for the stored procedure here
	@CreateTime	nvarchar(30) OUTPUT,
	@strUserId		nvarchar(20),	
	@nAccountID		int,
	@strAccountName	nvarchar(14),
	@nRace		tinyint,
	@nClass		tinyint,
	@nGender		int,
	@nHeadFaceColor	int,
	@nHeadHairColor	int,
	@nEyeColor		int,
	@nLipColor		int,
	@nHeadFaceType	tinyint,
	@nHeadHairType	tinyint,
	@fScale		float,
	@nVoiceType		tinyint,
	@nFeatType1		tinyint, -- 문신
	@nFeatType2		tinyint, -- 분장
	@nHeadBumpType	tinyint, -- bumpType
	@nHeadExpressionType	tinyint, -- 표정
	@nNameId		int,
	@nOrgServer		tinyint,
	@nWorld		int,
	@nXlocation		real,
	@nYlocation		real,
	@nZlocation		real,
	@nDir			tinyint,	
	@nHp			int,
	@nMp			int,
	@nBuilder		tinyint,

	-- customize
	@feat_version		tinyint,
	@feat_face_shape 	tinyint,
	@feat_forehead_shape 	tinyint,
	@feat_eye_position 	tinyint,
	@feat_eye_glabella 	tinyint,
	@feat_eye_length 	tinyint,
	@feat_eye_height 	tinyint,
	@feat_eye_shape 	tinyint,
	@feat_eye_tail 		tinyint,
	@feat_eyeblow_pos 	tinyint,
	@feat_eyeblow_angle 	tinyint,
	@feat_eyeblow_shape 	tinyint,
	@feat_nose_pos 		tinyint,
	@feat_nose_bridge 	tinyint,
	@feat_nose_side 	tinyint,
	@feat_nose_tip 		tinyint,
	@feat_cheek_shape 	tinyint,
	@feat_mouth_pos 	tinyint,
	@feat_mouth_size 	tinyint,
	@feat_lip_thickness 	tinyint,
	@feat_lip_tail 		tinyint,
	@feat_lip_shape 	tinyint,
	@feat_jaw_pos 		tinyint,
	@feat_jaw_shape 	tinyint,
	@feat_ear_shape		tinyint,
	@feat_head_size 	tinyint,
	@feat_neck_thickness 	tinyint,
	@feat_neck_length 	tinyint,
	@feat_shoulder_size 	tinyint,
	@feat_upper_size 	tinyint,
	@feat_bust_size 	tinyint,
	@feat_waist_size 	tinyint,
	@feat_hip_size 		tinyint,
	@feat_arm_thickness 	tinyint,
	@feat_hand_size 	tinyint,
	@feat_leg_thickness 	tinyint,
	@feat_foot_size 	tinyint,
	@feat_face_ratio 	tinyint,
	@feat_wing_size 	tinyint,
	@feat_arm_length 	tinyint,
	@feat_leg_length 	tinyint,
	@feat_shoulder_width 	tinyint,
	@feat_head_figure	tinyint -- 얼굴형태
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	set nocount on
	
	
DECLARE @CURR_TIME DateTime
SET @CURR_TIME = GetDate()

--DECLARE @UTC_ADJUST INT
--SET @UTC_ADJUST = dbo.GetUtcAdjustSecWithUTC_Local(GetUTCDate(), @CURR_TIME)
--SET @nCreateTime = dbo.GetUnixtimeWithUTCAdjust(@CURR_TIME, @UTC_ADJUST)
set @CreateTime = convert(nvarchar(30), @CURR_TIME, 126) 
	
-- 유저캐릭터아이디가 경계에 도달할때 캐릭터생성금지
IF IDENT_CURRENT('user_data') > 33550000
	return -1

IF EXISTS (SELECT char_id FROM user_data WHERE user_id=@strUserId AND (delete_date = 0 OR (delete_date > dbo.GetUnixtimeWithUTCAdjust(GetUTCDate(),0))))
	return -1

-- 금지캐릭터명 + 공통 금지어
-- forbidden_type
-- 0 : 공통
-- 1 : 캐릭터
-- 2 : 길드
-- forbidden_reason
-- 0 : GM 캐릭터
-- 1 : 일반 금지어
-- 2 : 캐릭터 사전 예약
-- 3 : 서버 이전	(1년간 재사용 금지)
-- 4 : 아이템 캐릭터 이름 변경 (1년간 재사용 금지)
-- 5 : 아이템 길드 이름 변경 (1년간 재사용 금지)
IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_word WHERE FORBIDDEN_WORD = @strUserId and IS_LIKE = 0 and status=0 and (forbidden_type=0 or forbidden_type=1))
	return -2	-- 금지 단어, GM 캐릭터

--IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_word WHERE FORBIDDEN_WORD LIKE '%'+@strName+'%' and IS_LIKE = 1 and status=0 and (forbidden_type=1 or forbidden_type=0)) 
IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_word WHERE (@strUserId LIKE '%' + FORBIDDEN_WORD + '%') and forbidden_word <> '' and IS_LIKE = 1 and status=0 and (forbidden_type=1 or forbidden_type=0))
	return -2	-- 금지어 포함


IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_char WHERE FORBIDDEN_CHAR=@strUserId and status=0 and (forbidden_reason in (3,4)) and (datediff(d, regdate, getdate()) < 366))
	return -2	-- 서버 이전이나, 캐릭터 이름 변경으로 1년간 사용 금지

-- 사전 예약
IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_char WHERE FORBIDDEN_CHAR=@strUserId and status=0 and forbidden_reason = 2)
	BEGIN
		IF NOT EXISTS (SELECT FORBIDDEN_ID FROM forbidden_char WHERE FORBIDDEN_CHAR=@strUserId and FORBIDDEN_ACCOUNT_NM=@strAccountName and status=0 and forbidden_reason = 2)
			return -3
	END

INSERT user_data (user_id,account_id, account_name, race, class, gender, 
	head_face_color, head_hair_color, head_eye_color, head_lip_color, head_face_type, head_hair_type, height_scale, head_voice_type, head_feat_type1, head_feat_type2,
