set @CreateTime = convert(nvarchar(30), @CURR_TIME, 126) 
	
-- 유저캐릭터아이디가 경계에 도달할때 캐릭터생성금지
IF IDENT_CURRENT('user_data') > 33550000
	return -1

IF EXISTS (SELECT char_id FROM user_data WHERE user_id=@strUserId AND (delete_date = 0 OR (delete_date > dbo.GetUnixtimeWithUTCAdjust(GetUTCDate(),0))))
	return -1

