	return -2	-- 서버 이전이나, 캐릭터 이름 변경으로 1년간 사용 금지

-- 사전 예약
IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_char WHERE FORBIDDEN_CHAR=@strUserId and status=0 and forbidden_reason = 2)
	BEGIN
		IF NOT EXISTS (SELECT FORBIDDEN_ID FROM forbidden_char WHERE FORBIDDEN_CHAR=@strUserId and FORBIDDEN_ACCOUNT_NM=@strAccountName and status=0 and forbidden_reason = 2)
