CREATE PROC [dbo].[GM_UserMonsterAchievement_UpdateOrInsert]
	@char_id	int,
	@achieve_id	int,
	@achieved_count	int,
	@achieved_grade	tinyint,
	@reward_received tinyint
AS
BEGIN
	UPDATE user_monster_achievement SET char_id=@char_id, achieve_id=@achieve_id, achieved_count=@achieved_count, achieved_grade=@achieved_grade, reward_received=@reward_received
