CREATE procedure [dbo].[aion_GetCharSeasonRankerId_byPoint]
	@rankId int,
	@minScore int
as
begin
	set nocount on
	select char_id, point 
	from user_rank (nolock) 
	where rank_id = @rankId and point >= @minScore
end

