	from user_rank (nolock) 
	where rank_id = @rankId and global_ranking <= @minScore and global_ranking != 0
end

procedures.aion_ClientSettingsPut:
/****** 개체: 저장 프로시저 dbo.aion_ClientSettingsPut    스크립트 날짜: 2006-02-20 오후 7:52:55 ******/


CREATE PROCEDURE [dbo].[aion_ClientSettingsPut]
(
	@char_id			int,
	@data_size		smallint,
	@data					varbinary(7168)	
)
AS
SET NOCOUNT ON
if exists (select char_id from user_client_settings(UPDLOCK) where char_id = @char_id) 
	begin
		update user_client_settings set data_size = @data_size, data = @data where char_id = @char_id
	end
else 
	begin
		insert user_client_settings(char_id, data_size, data) values (@char_id, @data_size, @data)
	end
SET NOCOUNT OFF

