CREATE PROCEDURE [dbo].[aion_PutCharInGameBlockPunishInfo]
	@accountId		int,
	@characterId	int,
	@punishCode		int,
	@remainMin		int,
	@punishReason	nvarchar(200)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	UPDATE user_punishment SET status = 1, cancel_date = GetDate() WHERE account_id = @accountId and char_id = @characterId and punish_code = @punishCode and status = 0
	
	INSERT INTO user_punishment(account_id, char_id, play_block, status, punish_code, start_date, end_date, remain_minute, punish_reason) 
	VALUES (@accountId, @characterId, 0, 0, @punishCode, GetDate(), DATEADD(minute, @remainMin, GetDate()), @remainMin, @punishReason)

	SET NOCOUNT OFF;
END

