	/* 1.9 추가 */
	@castingTimeRatio float, 
	@magicalCriticalRight int, 
	@magicalCriticalLeft int,	
	@phyCriticalReduceRate int,
	@magCriticalReduceRate int,
	@magCriticalDamageReduce int,
	@phyCriticalDamageReduce int,
	
	@healSkillBoost int,
	@mpHealSkillBoost int,
	@baseMagicalCriticalRight int,
