CREATE proc [dbo].[GM_UserDataDA_SrchUseBotChannelList]
			@world_id	int,
			@char_id	int,
			@user_id	nvarchar(20),
			@account_id	int,
			@account_name		nvarchar(20),
			@use_bot_channel	nvarchar(1),
			@page_num	int = 1,
			@view_count	int = 10000
		as
			declare @query	nvarchar(3000)
			declare @where	nvarchar(1000)
			declare @order_col	nvarchar(100)
			
			set @order_col = 'char_id desc'
			set @where = '
				where	delete_date = 0
				and		org_server = ' + CONVERT(nvarchar, @world_id)
			if (@char_id != 0)
				set @where = @where + '
				and		u.char_id = ' + CONVERT(nvarchar, @char_id)
			if (@user_id != '')
				set @where = @where + '
				and		user_id = ''' + @user_id + ''''
			if (@account_id != 0)
				set @where = @where + '
				and		u.account_id = ' + CONVERT(nvarchar, @account_id)
			if (@account_name != '')
				set @where = @where + '
				and		account_name = ''' + @account_name + ''''
			if (@use_bot_channel != '')
				set @where = @where + '
				and		ISNULL(use_bot_channel, 0) = ' + @use_bot_channel

			set @query = '
				select	top(' + CONVERT(nvarchar, @view_count) + ') * 
				from	(
					select	top(' + CONVERT(nvarchar, @page_num*@view_count) + ') ROW_NUMBER() over (order by u.' + @order_col + ') as num
							, u.char_id, user_id, u.account_id, account_name, class, gender, race, lev, builder, create_date, org_server, delete_date, delete_complete_date, delete_type
							, ISNULL(e.use_bot_channel, 0) as use_bot_channel, world, e.use_bot_channel_update_date as bot_update_date,
						case WHEN last_login_time = last_logout_time and last_login_time != ''1970-01-01 00:00:00.000'' and last_logout_time > ''2007-12-12 00:00:00.000'' THEN ''#339900''
						 WHEN last_login_time != last_logout_time or last_login_time = ''1970-01-01 00:00:00.000''  THEN ''brown''
						 WHEN last_login_time = last_logout_time and last_login_time != ''1970-01-01 00:00:00.000'' THEN ''black''
						 end as logonoff
					from	user_data u(nolock)
					left join user_extra_info e(nolock) on e.char_id = u.char_id ' +
					@where + '
					order by ' + @order_col + '
				) x 
				where	num > ' + CONVERT(nvarchar, (@page_num-1)*@view_count) + '
				order by ' + @order_col
			
			EXEC (@query)

