procedures.GM_UserPunishmentDAO_AddModPunishForBot:
CREATE PROCEDURE [dbo].[GM_UserPunishmentDAO_AddModPunishForBot]
	@account_id		int,
	@char_id		int,
	@play_block		tinyint,
	@status			tinyint,
	@punish_code	int,
--	@start_date		datetime,
--	@end_date		datetime,
	@punish_min		int,
--	@cancel_date	datetime,
--	@cancel_reason	nvarchar(200),
	@punish_reason	nvarchar(200),
	@login_id		nvarchar(30),
	@login_nm		nvarchar(30)	
AS
BEGIN
	
	IF NOT EXISTS ( SELECT 1 FROM user_punishment WHERE account_id = @account_id AND char_id = @char_id )
	BEGIN
		INSERT INTO user_punishment
		(
			account_id,
			char_id,
			play_block,
			status,
			punish_code,
			start_date,	
			end_date,
			remain_minute,
--			cancel_date,
--			cancel_reason,
			punish_reason,
			login_id,	
			login_nm
		)
		VALUES
		(
			@account_id,
			@char_id,
			@play_block,
			@status,
			@punish_code,
			GETDATE(),	
			DATEADD(minute, @punish_min, GETDATE()),
			@punish_min,
--			@cancel_date,
--			@cancel_reason,
			@punish_reason,
			@login_id,	
			@login_nm
		)
	END
	ELSE
	BEGIN
		UPDATE	user_punishment
		SET		punish_code = @punish_code
		WHERE	account_id = @account_id AND char_id = @char_id
	END

	RETURN @@ROWCOUNT

END

